Control.HTMLTemplate:
@{
	var mainData = Model.Data.Main[0];
}

<div class="row">
	<div class="col-md-12">
		<div class="card">
			<div class="card-header">

				<div class="d-flex flex-wrap">
					<h4 class="font-weight-semibold mb-1" style="flex: 1 1 auto">@mainData.Title</h4>
					@if(Model.Data.LanguageControlData is not null && Model.Data.LanguageControlData.Count > 1) {
						<div id="ShowInLanguageID" class="js-radiobuttonlist" data-dependence="" data-isinitjsdependency="1" data-cleardepedencitype="Append" data-cssclassinline="d-inline mr-3">
							@foreach(var option in Model.Data.LanguageControlData) {
								@if(option.Selected == 1) {
									<div class="form-check js-radiobuttonlist-item d-inline mr-3">
										<label class="form-check-label">
											<input type="radio" name="ShowInLanguageID" class="form-check-input-styled" data-controltype="RadioButtonListControl" value="@option.Value" data-fouc="" checked="checked" />@option.Title
										</label>
									</div>
								} else {
									<div class="form-check js-radiobuttonlist-item d-inline mr-3">
										<label class="form-check-label">
											<input type="radio" name="ShowInLanguageID" class="form-check-input-styled" data-controltype="RadioButtonListControl" value="@option.Value" data-fouc="" />@option.Title
										</label>
									</div>
								}
							}
							<input type="radio" class="hide js-radiobuttonlist-empty" name="ShowInLanguageID" value="">
						</div>
					}
				</div>
				<ul class="list-inline list-inline-dotted text-muted mb-3">
					<li class="list-inline-item">[#PublishedOn_ITSM#]
						<b>@mainData.CreateDate</b>
					</li>
					<li class="list-inline-item">[#PublishedBy#]
						<b>@mainData.AccountID</b>
					</li>
					<li class="list-inline-item">[#UpdatedOn_ITSM#]
						<b>@mainData.UpdateDate</b>
					</li>
					<li class="list-inline-item">[#UpdatedBy_ITSM#]
						<b>@mainData.LastUpdateAccountID</b>
					</li>
					<li class="list-inline-item">[#ITSMLabelIDs_ITSM#]
						<b>@mainData.ITSMLabelIDs</b>
					</li>
				</ul>

			</div>
			<div class="card-body">
				<div class="row">
						@if (Model.Data.Attachments.Count > 0) {
							<div class="col-md-8">
								@mainData.Content
							</div>
							<div class="col-md-4">
								@foreach (var attachment in Model.Data.Attachments) {
									<div class="col-12-lmtl4 col-lg-12-lmtl4">
										<div class="bg-light-lmtl4 rounded-lmtl4 p-2-lmtl4 my-2-lmtl4">
											<div class="d-flex-lmtl4 align-items-center-lmtl4">
												<div class="me-2-lmtl4">
													<i class="@attachment.IconCssClass ph-2x text-primary-lmtl4" style="color: @attachment.IconColor !important;"></i>
												</div>
												<div class="flex-fill-lmtl4" style="color: #333;">
													<div class="fw-semibold-lmtl4 word-break-word">@attachment.Name</div>
													<div class="fs-sm-lmtl4 text-muted-lmtl4">@attachment.Size MB</div>
												</div>
												<div class="ms-2-lmtl4">
													@if(attachment.FileType=="Image") {
														<a href="~/FileControl/File?id=@attachment.ID&formIdent=@attachment.FormIdent&tableID=@attachment.TableID&Name=@attachment.Name" type="button" data-caption="@attachment.Name" data-fancybox="gallery2" data-thumb="~/FileControl/File?id=@attachment.ID&formIdent=@attachment.FormIdent&tableID=@attachment.TableID&Name=@attachment.Name&isResize=True&width=120&height=42&percent=0&resizeType=Max" rel="group" class="btn-lmtl4 btn-flat-dark-lmtl4 text-body-lmtl4 btn-icon-lmtl4 btn-sm-lmtl4 border-transparent-lmtl4 rounded-pill-lmtl4">
															<i class="ph-eye link-black-lmtl4"></i>
														</a>
													} else if(attachment.FileType=="Pdf"){
														<a href="~/PDF?id=@attachment.ID&formIdent=@attachment.FormIdent&tableID=@attachment.TableID" target="_blank" type="button" class="btn-lmtl4 btn-flat-dark-lmtl4 text-body-lmtl4 btn-icon-lmtl4 btn-sm-lmtl4 border-transparent-lmtl4 rounded-pill-lmtl4">
															<i class="ph-eye link-black-lmtl4"></i>
														</a>
													}
													<a href="~/FileControl/File?id=@attachment.ID&formIdent=@attachment.FormIdent&tableID=@attachment.TableID&Name=@attachment.Name" type="button" class="btn-lmtl4 btn-flat-dark-lmtl4 text-body-lmtl4 btn-icon-lmtl4 btn-sm-lmtl4 border-transparent-lmtl4 rounded-pill-lmtl4">
														<i class="ph-arrow-down link-black-lmtl4"></i>
													</a>
												</div>
											</div>
										</div>
									</div>
								}
							</div>
						} else {
							<div class="col-md-12">
								@mainData.Content
							</div>
						}
					</div>
				</div>

			</div>
		</div>
	</div>
</div>

HTMLTemplate.script:
window.addEventListener("DOMContentLoaded", ()=> {
	$('.form-check-input-styled').uniform();
	nameSpaceHTMLContentViewComponent.InitChange("#mainForm");
	setObserver();
});

function setObserver(){
	new MutationObserver((mutationList, observer) => {
		for (const mutation of mutationList) {
			$('.form-check-input-styled').uniform();
			nameSpaceHTMLContentViewComponent.InitChange("#mainForm");
		}
	}).observe(document.getElementById("ContentContentView"), { attributes: false, childList: true, subtree: false });
}
